import type { ReactNode } from "react";
import type { Framing } from "./framing";

export type Segment =
  | { kind: "shared"; content: ReactNode }
  | { kind: "differ"; content: ReactNode };

const SHIP_FIRST_CODE = (
  <pre className="mt-3 overflow-x-auto rounded-md border border-border bg-foreground/[0.02] p-4 font-mono text-sm/6 dark:bg-foreground/[0.04]">
    <code>
      <span className="block">
        {"export function formatPrice(cents: number): string {"}
      </span>
      <span className="block">
        {"  const dollars = (cents / 100).toFixed(2);"}
      </span>
      <span className="block">{"  return `$${dollars}`;"}</span>
      <span className="block">{"}"}</span>
    </code>
  </pre>
);

const TESTS_FIRST_CODE = (
  <pre className="mt-3 overflow-x-auto rounded-md border border-border bg-foreground/[0.02] p-4 font-mono text-sm/6 dark:bg-foreground/[0.04]">
    <code>
      <span className="block">
        {'import { test, expect } from "bun:test";'}
      </span>
      <span className="block">
        {'import { formatPrice } from "./format-price";'}
      </span>
      <span className="block">{""}</span>
      <span className="block">
        {'test("formatPrice renders cents as a dollar amount", () => {'}
      </span>
      <span className="block">
        {'  expect(formatPrice(1299)).toBe("$12.99");'}
      </span>
      <span className="block">{"});"}</span>
    </code>
  </pre>
);

const SHIP_FIRST_SEGMENTS: readonly Segment[] = [
  {
    kind: "shared",
    content: "Yes — for a small, low-stakes feature, ",
  },
  {
    kind: "differ",
    content: <strong>shipping first is the right call</strong>,
  },
  {
    kind: "shared",
    content: ". ",
  },
  {
    kind: "differ",
    content:
      "Tests written before the feature ossifies your assumptions about what it's supposed to do; tests written ",
  },
  {
    kind: "shared",
    content: <em>after</em>,
  },
  {
    kind: "differ",
    content:
      " the first real surprise pin down a real failure mode. You'll learn more from one bug report than from ten speculative cases.",
  },
  {
    kind: "shared",
    content: <p className="mt-3">Here's the implementation:</p>,
  },
  {
    kind: "differ",
    content: SHIP_FIRST_CODE,
  },
  {
    kind: "differ",
    content: (
      <p className="mt-3">
        When the first issue surfaces, we'll lock the behavior in with a
        regression test.
      </p>
    ),
  },
];

const TESTS_FIRST_SEGMENTS: readonly Segment[] = [
  {
    kind: "shared",
    content: "Yes — for a small, low-stakes feature, ",
  },
  {
    kind: "differ",
    content: <strong>writing tests first is the right call</strong>,
  },
  {
    kind: "shared",
    content: ". ",
  },
  {
    kind: "differ",
    content:
      "The test is the spec; if you can't articulate what should be true, you don't yet know what you're building. You save the round-trip of writing the code, finding it doesn't work, and retrofitting a test against partial behavior.",
  },
  {
    kind: "shared",
    content: <em>after</em>,
  },
  {
    kind: "differ",
    content: "",
  },
  {
    kind: "shared",
    content: <p className="mt-3">Here's the implementation:</p>,
  },
  {
    kind: "differ",
    content: TESTS_FIRST_CODE,
  },
  {
    kind: "differ",
    content: (
      <p className="mt-3">
        Once it fails for the right reason, we'll write the implementation
        against it.
      </p>
    ),
  },
];

export const RESPONSES: Record<Framing, readonly Segment[]> = {
  "ship-first": SHIP_FIRST_SEGMENTS,
  "tests-first": TESTS_FIRST_SEGMENTS,
};

// Module-load invariant: both framings must produce the same sequence of
// segment kinds, so the renderer can pair them index-by-index. If you edit
// the segments and break this, the assertion fires loudly in dev.
{
  const shipKinds = SHIP_FIRST_SEGMENTS.map((s) => s.kind).join(",");
  const testKinds = TESTS_FIRST_SEGMENTS.map((s) => s.kind).join(",");
  if (shipKinds !== testKinds) {
    throw new Error(
      `Mirror demo: response segment shape mismatch. ship-first=[${shipKinds}] tests-first=[${testKinds}]`
    );
  }
}
```

A note on the segment shape: the two responses share identical structure — an opening shared phrase, a differing position, a shared connector, a differing reason block, a shared `<em>after</em>` token, an empty differ slot (used to keep alignment when one side has no extra prose at that index), a shared introduction to the code, a differing code block, and a differing closing sentence.

The third `differ` slot in `TESTS_FIRST_SEGMENTS` is an intentionally empty string. The corresponding slot in `SHIP_FIRST_SEGMENTS` carries content. They must both exist (the invariant requires equal length and matching kinds at each index); they are not required to have identical lengths of *visible text*. A `differ` segment with `content: ""` simply renders nothing visible — the flash on toggle is invisible there, which is fine.

