          aria-label={`Toggle approach. Currently: ${currentLabel}. Click to switch to: ${otherLabel}.`}
          className={cn(
            "inline-flex items-baseline gap-1.5 rounded-md border border-border/70 bg-foreground/[0.025] px-2 py-0.5 font-medium text-foreground/95 shadow-sm transition-colors hover:bg-foreground/[0.05] focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-ht-cyan-700/60 dark:bg-foreground/[0.04] dark:hover:bg-foreground/[0.07] dark:focus-visible:outline-ht-cyan-400/60"
          )}
          onClick={onToggle}
          type="button"
        >
