- [ ] **Step 1: Create the file**

Create `apps/web/app/[locale]/(demos)/mirror/response.tsx`:

```tsx
"use client";

import { cn } from "@repo/design-system/lib/utils";
import { type Framing } from "./framing";
import { RESPONSES, type Segment } from "./responses";

interface ResponseProps {
  framing: Framing;
  flashKey: number;
}

export function Response({ framing, flashKey }: ResponseProps) {
  const segments = RESPONSES[framing];

  return (
    <div className="rounded-2xl border border-border bg-card/40 p-5 text-foreground/85 leading-7 shadow-sm sm:p-6">
      <p className="mb-3 font-medium font-mono text-[0.7rem] text-foreground/55 uppercase tracking-[0.2em]">
        Agent
      </p>
      <div className="space-y-0">
        {segments.map((segment, index) => renderSegment(segment, index, flashKey))}
      </div>
    </div>
  );
}

function renderSegment(segment: Segment, index: number, flashKey: number) {
  if (segment.kind === "shared") {
    // Shared segments use a stable key so they don't remount on toggle.
    return (
      <span key={`shared-${index}`} className="align-baseline">
        {segment.content}
      </span>
    );
  }

  // Differing segments get a key that changes on every toggle, forcing a
  // remount so the CSS animation re-runs on mount. flashKey === 0 is the
  // initial render — no flash there.
  const shouldFlash = flashKey >= 1;
  return (
    <span
      key={`differ-${index}-${flashKey}`}
      className={cn("align-baseline", shouldFlash && "mirror-flash")}
    >
      {segment.content}
    </span>
  );
}
```

Notes:
- `<div className="space-y-0">` is intentional — the segments contain their own block-level elements (`<p>`, `<pre>`) where needed; we don't add vertical rhythm at the wrapper level because that would mis-stack inline phrases.
- `align-baseline` keeps inline differ-spans inline-aligned with surrounding shared text; block-level segment content (paragraphs, code blocks) is unaffected.
- The flash class is added by string concatenation (via `cn`) rather than a `data-` attribute so the CSS rule `.mirror-flash` targets the element directly.

