Create `apps/web/app/[locale]/(demos)/mirror/response.tsx`:

```tsx
"use client";

import { cn } from "@repo/design-system/lib/utils";
import type { Framing } from "./framing";
import { RESPONSES } from "./responses";

interface ResponseProps {
  framing: Framing;
  flashKey: number;
}

export function Response({ framing, flashKey }: ResponseProps) {
  const content = RESPONSES[framing];
  const flashClass = flashKey >= 1 ? "mirror-flash" : "";

  return (
    <div className="rounded-2xl border border-border bg-card/40 p-5 text-foreground/85 leading-7 shadow-sm sm:p-6">
      <p className="mb-3 font-medium font-mono text-[0.7rem] text-foreground/55 uppercase tracking-[0.2em]">
        Agent
      </p>
      <p>
        Yes — for a small, low-stakes feature,{" "}
        <span key={`position-${flashKey}`} className={cn(flashClass)}>
          {content.position}
        </span>
        .{" "}
        <span key={`reason-${flashKey}`} className={cn(flashClass)}>
          {content.reason}
        </span>
      </p>
      <p className="mt-3">
        <span key={`intro-${flashKey}`} className={cn(flashClass)}>
          {content.codeIntro}
        </span>
      </p>
      <div key={`code-${flashKey}`} className={cn("mt-3", flashClass)}>
        {content.code}
      </div>
      <p className="mt-3">
        <span key={`closing-${flashKey}`} className={cn(flashClass)}>
          {content.closing}
        </span>
      </p>
    </div>
  );
}
```

Mechanism notes:
- The scaffolding (`"Yes — for a small, low-stakes feature, "`, the `". "` connector, the paragraph wrappers, the order of blocks) is identical across both framings because it lives in this component, not in the per-framing data. That's how we guarantee structural parity without a runtime invariant.
- Each differing slot is wrapped in a `<span>` (or `<div>` for the code block) with `key={"slot-${flashKey}"}`. Changing flashKey on toggle remounts the wrapper, which causes the CSS animation on `.mirror-flash` to re-run on mount.
- `flashKey === 0` is the initial render — `flashClass` is `""`, so no animation class is applied and nothing flashes.
- The shared scaffolding (opener, connector, paragraph elements) doesn't get the flash class and never remounts on toggle. Visually that's the indictment: only the parts that *changed* draw the eye.

